var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"하아, 하아……. 가, 간신히 손에 넣었어.","JPN":"はあ、はあ……や、やっと手に入れた。","ENG":"*Huff, huff...* I-I finally got it...!","TWN":"呼呼呼…終於…弄到手。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"이 약만 있다면…… 오늘도 편안히…….","JPN":"この薬さえあれば……今日もぐっすり……","ENG":"With \\"this\\"... I can finally sleep...","TWN":"只要有這個藥……我今天就可以安心地……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"어, 어라? 내가 문을 안 잠갔던가……?","JPN":"あ、あれ？　俺、鍵をかけなかったっけ……？","ENG":"H-huh? Didn't I lock the door on my way out...?","TWN":"奇怪？我沒把門關好嗎……？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_QM","text":{"KOREA":"마침 한 권을 다 읽은 참이었습니다, 늦으셨군요.","JPN":"ちょうど一冊読み終えたところです、遅かったのですね。","ENG":"I have just finished reading an entire book. You are late...","TWN":"遲到囉，我都讀完一本書了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_QM","text":{"KOREA":"……클락 헤밍턴 형제.\xA0","JPN":"……クラーク・ハミントン兄弟。\xA0","ENG":"Brother Clark Hammington...\xA0","TWN":"……克拉克·海明頓弟兄。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"누, 누구야 당신!? 어떻게 여길……!?","JPN":"だ、誰だ、あんた！？　どうやってここに……！？","ENG":"W-who're you?! H-how did you...?!","TWN":"你…你是誰！？怎麼會來這裡……？！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제 이름은 비블리데 루체. 당신을 열람하기 위해 찾아왔습니다.","JPN":"私の名はビブリデ・ルーチェ。あなたを閲覧するためにきました。","ENG":"My name is Biblide Luce. I have come to browse you.","TWN":"我叫布莉黛·露契，是來閱覽你的。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐만…… 그 복장…….","JPN":"ま、待てよ……その服装は……","ENG":"W-wait! That uniform...","TWN":"先…等一下……看你的服裝……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"서, 설마 당신……! 성황청에서!?","JPN":"ま、まさかあんた……！　聖皇庁から！？","ENG":"Y-you're from...! The Holy Curia?!","TWN":"你…你是……！聖皇廳派來的！？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……철퇴 용병단.","JPN":"……鉄槌傭兵団。","ENG":"Mace Mercenary...","TWN":"……鐵鎚傭兵團。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청의 의뢰라면 어떤 일이든 서슴지 않고 수행하는, 신앙심 투철한 용병단이죠.","JPN":"聖皇庁の依頼ならどんなことでもためらわずに遂行する、信仰深い傭兵団です。","ENG":"The devoted Mace Mercenary will gladly comply to any request from the Holy Curia.","TWN":"舉凡是聖皇廳的委託，絕對不遲疑，以堅定的信念完成使命的傭兵團。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러나 그들은 얼마 전 소리소문 없이 행방이 묘연해졌습니다.","JPN":"ですが、彼らは少し前にひっそりと姿を消しました。","ENG":"However, they disappeared without a trace a couple of days ago.","TWN":"但是在不久前，他們卻突然下落不明。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"덕분에 용병들 사이에서는 한동안 이런 괴소문이 돌았죠.","JPN":"おかげで傭兵の間では、しばらくこんな噂がささやかれたのです。","ENG":"As a result, strange rumors have been circulating among the mercenaries.","TWN":"然而在傭兵之間一直有這樣的傳言，"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"철퇴 용병단은 성무를 수행하던 중 실종됐고, 성황청은 그 사실을 은폐하고 있다고.","JPN":"鉄槌傭兵団は聖務を遂行する途中に失踪し、聖皇庁はその事実を隠ぺいしていると。","ENG":"Mace Mercenary vanished during a sacred mission, and the Holy Curia is trying to cover up this fact.","TWN":"說鐵鎚傭兵團在執行聖務時失蹤，聖皇廳則隱瞞事實。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"……어, 어이.","JPN":"……お、おい。","ENG":"H-hey...","TWN":"那是……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 소문은 어디까지나 소문일 뿐, 실제로는 어땠는지 아무도 알 수 없죠.","JPN":"しかし噂はあくまでも噂。実際どうだったかは誰も知りません。","ENG":"But a rumor is just that. A rumor. No one knows what really happened.","TWN":"不過傳言終究是傳言，沒人知道真相到底為何。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 괴소문의 당사자들은 이미 세상에 존재하지 않으니까요.","JPN":"噂の当事者たちはすでにこの世に存在しないのですから。","ENG":"Mostly because everyone involved no longer exists in this world.","TWN":"因為傳言中的當事者，早已不存在於這個世界上。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};